const scriptPacket = $json.final_script_packet || { payload: { target_platform: 'generic', metadata: {} } };
const platforms = { youtube: { tools: ['video_editor', 'subtitle_generator'], constraints: ['max_length_4h', 'quality_1080p_min'] }, blog: { tools: ['markdown_renderer', 'image_optimizer'], constraints: ['plain_text_only', 'no_video'] }, podcast: { tools: ['audio_optimizer', 'transcript_generator'], constraints: ['audio_only', 'max_bitrate_192kbps'] }, email: { tools: ['html_renderer', 'link_tracker'], constraints: ['plain_text_fallback', 'max_width_600px'] } };
const platform = scriptPacket.payload?.target_platform || 'generic';
const allowedTools = platforms[platform]?.tools || ['generic_renderer'];
const constraints = platforms[platform]?.constraints || ['generic_constraints'];
const contextEnvelope = { instance_id: 'CTX-' + Date.now(), platform: platform, allowed_tools: allowedTools, forbidden_tools: ['shell_execution', 'external_api_call_untracked'], execution_constraints: constraints, quality_gates: { min_coherence: 0.85, min_accuracy: 0.90 } };
return [{ json: { ...$json, context_envelope: contextEnvelope, execution_context_built: true } }];

const packet = {
  instance_id: $json.context_envelope.instance_id,
  artifact_family: 'execution_context_packet',
  schema_version: '1.0.0',
  producer_workflow: 'CWF-310',
  dossier_ref: $json.dossier_id || 'DOSSIER-UNSPECIFIED',
  created_at: new Date().toISOString(),
  status: 'CREATED',
  payload: {
    execution_context_built: true,
    target_platform: $json.context_envelope.platform,
    allowed_tools: $json.context_envelope.allowed_tools,
    forbidden_tools: $json.context_envelope.forbidden_tools,
    execution_constraints: $json.context_envelope.execution_constraints,
    quality_gates: $json.context_envelope.quality_gates
  }
};
return [{ json: { ...$json, execution_context_packet: packet, packet_emitted: true } }];
